	FinishWebAuthnRegistration(context.Context, *connect.Request[v1.FinishWebAuthnRegistrationRequest]) (*connect.Response[v1.FinishWebAuthnRegistrationResponse], error)
	BeginWebAuthnLogin(context.Context, *connect.Request[v1.BeginWebAuthnLoginRequest]) (*connect.Response[v1.BeginWebAuthnLoginResponse], error)
	FinishWebAuthnLogin(context.Context, *connect.Request[v1.FinishWebAuthnLoginRequest]) (*connect.Response[v1.FinishWebAuthnLoginResponse], error)
	BeginDiscoverableWebAuthnLogin(context.Context, *connect.Request[v1.BeginDiscoverableWebAuthnLoginRequest]) (*connect.Response[v1.BeginDiscoverableWebAuthnLoginResponse], error)
	FinishDiscoverableWebAuthnLogin(context.Context, *connect.Request[v1.FinishDiscoverableWebAuthnLoginRequest]) (*connect.Response[v1.FinishDiscoverableWebAuthnLoginResponse], error)
